public static boolean areSentencesSimilar(String[] sentence1, String[] sentence2, String[][] pairs) {
        // Check if lengths of both sentences are equal
        if (sentence1.length != sentence2.length) {
            return false;
        }

        // Build a HashMap to store word similarities
        HashMap<String, String> wordSimilarities = new HashMap<>();

        // Populate the HashMap with given word pairs
        for (String[] pair : pairs) {
            wordSimilarities.put(pair[0], pair[1]);
            wordSimilarities.put(pair[1], pair[0]);
        }

        // Compare corresponding words in the two sentences
        for (int i = 0; i < sentence1.length; i++) {
            String word1 = sentence1[i];
            String word2 = sentence2[i];

            // Check if words are equal or similar
            if (!word1.equals(word2) && !wordSimilar(word1, word2, wordSimilarities)) {
                return false;
            }
        }

        return true;
    }

    private static boolean wordSimilar(String word1, String word2, HashMap<String, String> wordSimilarities) {
        // Check if words are similar using the HashMap
        return wordSimilarities.containsKey(word1) && wordSimilarities.get(word1).equals(word2);
    }
